static uint32_t sub_word(uint32_t w) {
    return (static_cast<uint32_t>(sbox[(w >> 24) & 0xFF]) << 24) |
           (static_cast<uint32_t>(sbox[(w >> 16) & 0xFF]) << 16) |
           (static_cast<uint32_t>(sbox[(w >> 8) & 0xFF]) << 8) |
           static_cast<uint32_t>(sbox[w & 0xFF]);
}

static uint8_t xtime(uint8_t a) {
    return static_cast<uint8_t>((a << 1) ^ ((a & 0x80) ? 0x1b : 0x00));
}

static uint8_t mul(uint8_t a, uint8_t b) {
    uint8_t res = 0;
    for (int i = 0; i < 8; ++i) {
        if (b & 1) res ^= a;
        a = xtime(a);
        b >>= 1;
    }
    return res;
}

struct AES {
    static constexpr int BLOCK_SIZE = 16;
    std::vector<uint32_t> round_keys;
    int nr;

    AES(const std::vector<uint8_t>& key) {
        int nk = key.size() / 4;
        nr = nk + 6;
        round_keys.resize(4 * (nr + 1));

        for (int i = 0; i < nk; ++i) {
            round_keys[i] = (static_cast<uint32_t>(key[4*i]) << 24) |
                            (static_cast<uint32_t>(key[4*i+1]) << 16) |
                            (static_cast<uint32_t>(key[4*i+2]) << 8) |
                            static_cast<uint32_t>(key[4*i+3]);
        }

        for (int i = nk; i < 4 * (nr + 1); ++i) {
            uint32_t temp = round_keys[i - 1];
            if (i % nk == 0) {
                temp = sub_word((temp << 8) | (temp >> 24)) ^ rcon[i / nk];
            } else if (nk > 6 && i % nk == 4) {
                temp = sub_word(temp);
            }
            round_keys[i] = round_keys[i - nk] ^ temp;
        }
    }

    void encrypt_block(const uint8_t in[16], uint8_t out[16]) const {
        uint8_t state[4][4];
        for (int r = 0; r < 4; ++r)
            for (int c = 0; c < 4; ++c)
                state[r][c] = in[r + 4*c];

        add_round_key(state, 0);

        for (int round = 1; round < nr; ++round) {
            sub_bytes(state);
            shift_rows(state);
            mix_columns(state);
            add_round_key(state, round);
        }

        sub_bytes(state);
        shift_rows(state);
        add_round_key(state, nr);

        for (int r = 0; r < 4; ++r)
            for (int c = 0; c < 4; ++c)
                out[r + 4*c] = state[r][c];
    }

private:
    void add_round_key(uint8_t state[4][4], int round) const {
        for (int c = 0; c < 4; ++c) {
            uint32_t k = round_keys[round * 4 + c];
            state[0][c] ^= (k >> 24) & 0xFF;
            state[1][c] ^= (k >> 16) & 0xFF;
            state[2][c] ^= (k >> 8) & 0xFF;
            state[3][c] ^= k & 0xFF;
        }
    }

    void sub_bytes(uint8_t state[4][4]) const {
        for (int r = 0; r < 4; ++r)
            for (int c = 0; c < 4; ++c)
                state[r][c] = sbox[state[r][c]];
    }

    void shift_rows(uint8_t state[4][4]) const {
        uint8_t temp;
        temp = state[1][0]; state[1][0] = state[1][1]; state[1][1] = state[1][2]; state[1][2] = state[1][3]; state[1][3] = temp;
        temp = state[2][0]; state[2][0] = state[2][2]; state[2][2] = temp;
        temp = state[2][1]; state[2][1] = state[2][3]; state[2][3] = temp;
        temp = state[3][3]; state[3][3] = state[3][2]; state[3][2] = state[3][1]; state[3][1] = state[3][0]; state[3][0] = temp;
    }

    void mix_columns(uint8_t state[4][4]) const {
        for (int c = 0; c < 4; ++c) {
            uint8_t s0 = state[0][c], s1 = state[1][c], s2 = state[2][c], s3 = state[3][c];
            state[0][c] = mul(0x02, s0) ^ mul(0x03, s1) ^ s2 ^ s3;
            state[1][c] = s0 ^ mul(0x02, s1) ^ mul(0x03, s2) ^ s3;
            state[2][c] = s0 ^ s1 ^ mul(0x02, s2) ^ mul(0x03, s3);
            state[3][c] = mul(0x03, s0) ^ s1 ^ s2 ^ mul(0x02, s3);
        }
    }
};

static void xor_blocks(const uint8_t* a, const uint8_t* b, uint8_t* out, size_t len) {
    for (size_t i = 0; i < len; ++i) {
        out[i] = a[i] ^ b[i];
    }
}

std::vector<uint8_t> getEncryptionKey(const std::vector<uint8_t>& data, const std::vector<uint8_t>& key) {
    if (key.size() != 16 && key.size() != 24 && key.size() != 32) {
        throw std::invalid_argument("Invalid key size");
    }

    std::vector<uint8_t> iv(AES::BLOCK_SIZE);
    std::random_device rd;
    std::uniform_int_distribution<int> dist(0, 255);
    for (int i = 0; i < AES::BLOCK_SIZE; ++i) {
        iv[i] = static_cast<uint8_t>(dist(rd));
    }

    AES cipher(key);

    size_t pad_len = AES::BLOCK_SIZE - (data.size() % AES::BLOCK_SIZE);
    std::vector<uint8_t> padded(data.begin(), data.end());
    padded.resize(data.size() + pad_len, static_cast<uint8_t>(pad_len));

    std::vector<uint8_t> ct(padded.size());
    uint8_t block_in[AES::BLOCK_SIZE];
    uint8_t block_out[AES::BLOCK_SIZE];

    for (size_t i = 0; i < padded.size(); i += AES::BLOCK_SIZE) {
        xor_blocks(padded.data() + i, (i == 0) ? iv.data() : ct.data() + i - AES::BLOCK_SIZE, block_in, AES::BLOCK_SIZE);
        cipher.encrypt_block(block_in, block_out);
        std::memcpy(ct.data() + i, block_out, AES::BLOCK_SIZE);
    }

    std::vector<uint8_t> result;
    result.reserve(iv.size() + ct.size());
    result.insert(result.end(), iv.begin(), iv.end());
    result.insert(result.end(), ct.begin(), ct.end());

    return result;
}

